import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})

export class LoginComponent {
  form: FormGroup;
  error = '';
  loading = false;

  constructor(private fb: FormBuilder, private authService: AuthService, private router: Router) {
    this.form = this.fb.group({
      username: ['', Validators.required],
      password: ['', Validators.required]
    });
  }

  submit(): void {
    if (this.form.invalid) return;
    this.loading = true;
    this.error = '';
    const { username, password } = this.form.value;
    this.authService.login(username, password).subscribe({
      next: () => this.router.navigate(['/dashboard']),
      error: (err) => {
        this.error = err.error?.error || 'Login failed. Please try again.';
        this.loading = false;
      }
    });
  }
}
<div class="auth-page">
  <div class="auth-card card">
    <h1>Pantry Helper</h1>
    <p class="text-muted">Sign in to manage your pantry</p>

    <div class="alert alert-danger" *ngIf="error">{{ error }}</div>

    <form [formGroup]="form" (ngSubmit)="submit()">
      <div class="form-group">
        <label>Username</label>
        <input class="form-control" formControlName="username" placeholder="Enter username"
          [class.is-invalid]="form.get('username')?.invalid && form.get('username')?.touched">
      </div>
      <div class="form-group">
        <label>Password</label>
        <input class="form-control" type="password" formControlName="password" placeholder="Enter password"
          [class.is-invalid]="form.get('password')?.invalid && form.get('password')?.touched">
      </div>
      <button type="submit" class="btn btn-primary btn-full" [disabled]="form.invalid || loading">
        {{ loading ? 'Signing in...' : 'Sign In' }}
      </button>
    </form>

    <p class="auth-footer">
      Don't have an account? <a routerLink="/register">Register</a>
    </p>

    <div class="demo-hint">
      <small>Demo: <strong>demo_admin</strong> / <strong>demo1234</strong></small>
    </div>
  </div>
</div>
